import { Queue, Worker } from "bullmq";
import { getRedis } from "../../../api/src/lib/redis";

interface OutboundMessage {
  sessionId: string;
  to: string;
  type: string;
  content: string;
  mediaUrl?: string;
}

/**
 * Message queue for outbound WhatsApp messages
 */
export class MessageQueue {
  private queue: Queue;

  constructor() {
    this.queue = new Queue("whatsapp-outbound", {
      connection: { host: "localhost", port: 6379 },
      defaultJobOptions: {
        attempts: 3,
        backoff: { type: "exponential", delay: 2000 },
        removeOnComplete: 1000,
        removeOnFail: 5000,
      },
    });

    this.initWorker();
  }

  async enqueue(message: OutboundMessage) {
    const job = await this.queue.add("send-message", message, {
      priority: 1,
    });
    return { jobId: job.id, status: "queued" };
  }

  async enqueueBulk(messages: OutboundMessage[]) {
    const jobs = await this.queue.addBulk(
      messages.map((msg, index) => ({
        name: "send-message",
        data: msg,
        opts: { priority: 2, delay: index * 1000 }, // 1s delay between messages
      }))
    );
    return { count: jobs.length, status: "queued" };
  }

  private initWorker() {
    const worker = new Worker(
      "whatsapp-outbound",
      async (job) => {
        const message = job.data as OutboundMessage;
        console.log(`[Queue] Sending message to ${message.to}`);

        // TODO: Route to correct provider and send
        // await this.sendViaProvider(message);

        return { sent: true, timestamp: Date.now() };
      },
      {
        connection: { host: "localhost", port: 6379 },
        concurrency: 5,
        limiter: { max: 30, duration: 1000 }, // 30 messages per second
      }
    );

    worker.on("completed", (job) => {
      console.log(`[Queue] Message ${job.id} sent successfully`);
    });

    worker.on("failed", (job, err) => {
      console.error(`[Queue] Message ${job?.id} failed:`, err.message);
    });
