## 🎯 System Design Patterns

### 1. Multi-Tenant Architecture

#### Tenant Isolation Strategy

```typescript
// Data Isolation at Database Level
// Every query must include tenantId

// ✅ Good: Tenant-scoped query
const contacts = await prisma.contact.findMany({
  where: { tenantId: req.user.tenantId },
});

// ❌ Bad: Missing tenant filter
const contacts = await prisma.contact.findMany();

// Enforce at middleware level
app.use("*", async (c, next) => {
  const tenantId = c.req.header("X-Tenant-ID");
  if (!tenantId) {
    return c.json({ error: "Missing tenant ID" }, 400);
  }
  c.set("tenantId", tenantId);
  await next();
});
```

#### Tenant Context Pattern

```typescript
// Create tenant context for each request
interface TenantContext {
  tenantId: string;
  userId: string;
  userRole: UserRole;
  permissions: string[];
}

// Middleware to attach context
app.use("*", async (c, next) => {
  const token = c.req.header("Authorization")?.replace("Bearer ", "");
  const decoded = jwt.verify(token, JWT_SECRET);

  const member = await prisma.tenantMember.findUnique({
    where: {
      tenantId_userId: {
        tenantId: decoded.tenantId,
        userId: decoded.userId,
      },
    },
  });

  c.set("tenantContext", {
    tenantId: decoded.tenantId,
    userId: decoded.userId,
    userRole: member.role,
    permissions: getPermissions(member.role),
  });

  await next();
});

// Use in services
class ContactService {
  async getContacts(tenantContext: TenantContext) {
    return prisma.contact.findMany({
      where: { tenantId: tenantContext.tenantId },
    });
  }
}
```

#### Tenant-specific Configuration

```typescript
// Store tenant settings in database
model Tenant {
  id: string;
  name: string;
  settings: Json; // { theme, language, features, limits }
  metadata: Json; // { customDomain, logo, branding }
}

// Load tenant config on request
const getTenantConfig = async (tenantId: string) => {
  const cached = await redis.get(`tenant:config:${tenantId}`);
  if (cached) return JSON.parse(cached);

  const tenant = await prisma.tenant.findUnique({
    where: { id: tenantId },
  });

  await redis.setex(
    `tenant:config:${tenantId}`,
    3600,
    JSON.stringify(tenant)
  );

  return tenant;
};
```

