#### Repository Implementation

```typescript
// apps/api/src/modules/contacts/repository.ts

export class ContactRepository {
  async findById(id: string, tenantId: string) {
    return prisma.contact.findUnique({
      where: { id },
    }).then(contact => {
      if (contact?.tenantId !== tenantId) return null;
      return contact;
    });
  }

  async findByPhone(phone: string, tenantId: string) {
    return prisma.contact.findUnique({
      where: { tenantId_phone: { tenantId, phone } },
    });
  }

  async findMany(tenantId: string, filters: FilterInput) {
    return prisma.contact.findMany({
      where: { tenantId, ...filters },
      orderBy: { createdAt: "desc" },
    });
  }

  async create(tenantId: string, data: CreateContactInput) {
    return prisma.contact.create({
      data: { tenantId, ...data },
    });
  }

  async update(id: string, tenantId: string, data: UpdateContactInput) {
    const contact = await this.findById(id, tenantId);
    if (!contact) throw new Error("Contact not found");

    return prisma.contact.update({
      where: { id },
      data,
    });
  }

  async delete(id: string, tenantId: string) {
    const contact = await this.findById(id, tenantId);
    if (!contact) throw new Error("Contact not found");

    return prisma.contact.delete({ where: { id } });
  }
}
