## ⚙️ Concurrency Model

### 1. Async/Await Pattern

```typescript
// Sequential execution
async function processMessages(messages: Message[]) {
  for (const message of messages) {
    await processMessage(message); // Wait for each
  }
}

// Parallel execution
async function processMessages(messages: Message[]) {
  await Promise.all(messages.map(m => processMessage(m))); // All at once
}

// Controlled concurrency
async function processMessages(messages: Message[], concurrency = 5) {
  const queue = [...messages];
  const active = [];

  while (queue.length > 0 || active.length > 0) {
    while (active.length < concurrency && queue.length > 0) {
      const message = queue.shift();
      active.push(
        processMessage(message).finally(() => {
          active.splice(active.indexOf(promise), 1);
        })
      );
    }
    await Promise.race(active);
  }
}
```

