// apps/api/src/lib/metrics.ts

export class Metrics {
  private requestCount = 0
  private requestDuration: number[] = []
  private errorCount = 0

  recordRequest(duration: number) {
    this.requestCount++
    this.requestDuration.push(duration)
  }

  recordError() {
    this.errorCount++
  }

  getMetrics() {
    return {
      requestCount: this.requestCount,
      averageDuration: this.requestDuration.reduce((a, b) => a + b, 0) / this.requestDuration.length,
      errorCount: this.errorCount,
      errorRate: this.errorCount / this.requestCount,
    }
  }
}

// apps/api/src/middleware/metrics.ts

export const metricsMiddleware = (metrics: Metrics) => {
  return async (c: Context, next: Next) => {
    const start = Date.now()

    try {
      await next()
    } catch (error) {
      metrics.recordError()
      throw error
    } finally {
      const duration = Date.now() - start
      metrics.recordRequest(duration)
    }
  }
}

// Add metrics endpoint
app.get("/metrics", (c) => {
  return c.json(metrics.getMetrics())
})
```

