      const hash = await authService.hashPassword(password)

      expect(hash).not.toBe(password)
      expect(await authService.verifyPassword(password, hash)).toBe(true)
    })

    it("should reject wrong password", async () => {
      const password = "test123"
      const hash = await authService.hashPassword(password)

      expect(await authService.verifyPassword("wrong", hash)).toBe(false)
    })
  })

  describe("generateToken", () => {
    it("should generate valid JWT token", () => {
      const token = authService.generateToken({ userId: "user_123" })

      expect(token).toBeDefined()
      expect(typeof token).toBe("string")

      const decoded = authService.verifyToken(token)
      expect(decoded.userId).toBe("user_123")
    })

    it("should reject expired token", () => {
      // Mock expired token
      expect(() => authService.verifyToken("expired_token")).toThrow()
    })
  })

  describe("login", () => {
    it("should login successfully with correct credentials", async () => {
      // Mock user
      const result = await authService.login("user@example.com", "password123")

      expect(result).toHaveProperty("accessToken")
      expect(result).toHaveProperty("refreshToken")
      expect(result).toHaveProperty("user")
    })

